import React from "react";
import { Container, Sleeve, VinylRecord, Circle } from "./styles";
import templeSmoke from "../../Assets/temple_smoke.png";
import { getColors } from "../../Styles/colors";

const RecordCover: React.FC = () => {
  return (
    <Container>
      <VinylRecord>
        <Circle diameter={34} />
        <Circle diameter={32} />
        <Circle diameter={30} />
        <Circle diameter={28} />
        <Circle diameter={26} />
        <Circle diameter={24} />
        <Circle diameter={22} />
        <Circle diameter={20} />
        <Circle diameter={18} />
        <Circle diameter={16} />
        <Circle diameter={14} color={"white"} />
        <Circle diameter={3} color={"black"} />
      </VinylRecord>
      <Sleeve src={templeSmoke}></Sleeve>
    </Container>
  );
};

export default RecordCover;
